// Fila de magia do jogador
let magicQueue = { dmgExtra: 0, healExtra: 0, area: null, effect: null, support: null, revive: false, mpCost: 0 };
// area: null | 'two' (3 MP, 2 alvos) | 'all' (5 MP, todos)

function mpCostQueue() {
  if (magicQueue.revive) return 10; // Reviver ├й sempre independente, custo fixo
  let cost = magicQueue.dmgExtra * 2;
  cost += magicQueue.healExtra * 2;
  if (magicQueue.area === 'two') cost += 3;
  else if (magicQueue.area === 'all') cost += 5;
  if (magicQueue.effect)  { cost += magicQueue.effect.cost; }
  if (magicQueue.support) { cost += magicQueue.support.cost; }
  const typeCount = [
    magicQueue.dmgExtra > 0,
    magicQueue.healExtra > 0,
    !!magicQueue.area,
    !!magicQueue.effect,
    !!magicQueue.support
  ].filter(Boolean).length;
  if (typeCount >= 2) cost += typeCount - 1;
  return cost;
}

